/// <reference lib="webworker" />
// sw.ts ‚Äî Serwist service worker (generated by Nous, IMP-238).
// IMP-248 ‚Äî the `webworker` lib reference above brings `ServiceWorkerGlobalScope`
// into scope (the project tsconfig targets DOM, not WebWorker), so `tsc`
// resolves the service-worker global type instead of TS2552.
import { defaultCache } from "@serwist/next/worker";
import { NetworkOnly, Serwist } from "serwist";

import { isTenantExportRoutePath } from "@/lib/admin-export-route-policy";

declare const self: ServiceWorkerGlobalScope & {
  __SW_MANIFEST: (string | { url: string; revision: string | null })[];
};

const serwist = new Serwist({
  precacheEntries: self.__SW_MANIFEST,
  skipWaiting: true,
  clientsClaim: true,
  navigationPreload: true,
  runtimeCaching: [
    {
      matcher: ({ sameOrigin, url: { pathname } }) =>
        sameOrigin && isTenantExportRoutePath(pathname),
      method: "GET",
      handler: new NetworkOnly(),
    },
    ...defaultCache,
  ],
});

self.addEventListener("message", (event) => {
  if (event.data?.type === "MI_BANQUITO_OUTBOX_COUNT") {
    self.clients.matchAll({ type: "window" }).then((clients) => {
      for (const client of clients) {
        client.postMessage({
          type: "MI_BANQUITO_OUTBOX_COUNT",
          count: event.data.count,
        });
      }
    });
  }
});

serwist.addEventListeners();
